		fmt_kr = '6. 회장과 부회장은 가입 심사 및 회원 추방 등을 진행할 수 있습니다.',
		fmt_pt = '6. Tanto o líder quanto o líder assistente estão autorizados a aprovar solicitações, expulsar membros, etc.',
		fmt_th = '6. ทั้งผู้นำและผู้ช่วยผู้นำมีอำนาจในการอนุมัติคำขอ ไล่สมาชิกออก ฯลฯ'
	},
	[11006] = {
		id = 11006,
		fmt = '7.会长连续5天不上线，将会按照副会长>会员的优先级，传位给期间满足上线条件、贡献度最高的玩家，与其职位互换',
		fmt_tw = '7.會長連續5天不上線，將會按照副會長>會員的優先順序，傳位給期間滿足上線條件、貢獻度最高的玩家，與其職位互換',
		fmt_en = '7. If the union Leader does not come online for 5 consecutive days, the role will be transferred to the one who meets all the requirements, has the highest contribution level and according to the order of Assistant Leader > Member priority',
		fmt_kr = '7. 회장이 5일 연속 접속하지 않을 시 부회장, 회원 순서로 접속 조건에 맞는 공헌도가 가장 높은 유저에게 회장 직위가 양도됩니다.',
		fmt_pt = '7. Se o líder sindical não estiver online por 5 dias consecutivos, a função será transferida para aquele que atender a todos os requisitos, tiver o maior nível de contribuição e de acordo com a ordem de Líder Assistente > Prioridade do membro.',
		fmt_th = '7. หากผู้นำสหภาพไม่มาทำงานติดต่อกัน 5 วัน บทบาทดังกล่าวจะถูกโอนไปยังผู้ที่ตรงตามข้อกำหนดทั้งหมด ผู้ที่มีระดับการสนับสนุนสูงสุด และตามลำดับความสำคัญของผู้ช่วยผู้นำ > สมาชิก'
	},
	[11007] = {
		id = 11007,
		fmt = '8.会长需将会长职位传给其他玩家才能离开公会',
		fmt_tw = '8.會長需將會長職位傳給其他玩家才能離開公會',
