	[19001] = {
		id = 19001,
		fmt = '#C0xFFF5D6#1.玩家可在公会红包里进行发红包和抢红包，红包有个数限定，可要抓紧咯',
		fmt_tw = '#C0xFFF5D6#1.玩家可在公會紅包裡進行發紅包和搶紅包，紅包有個數限定，可要抓緊咯',
		fmt_en = '#C0xFFF5D6#1. Players can send Red Packets or grab Red Packets in the guild. As there are a limited number of Red Packets, the fastest finger gets it first!',
		fmt_vn = '#C0xFFF5D6#1.Người chơi phát và cướp Lì Xì trong Lì Xì Guild, số lượng Lì Xì có hạn, nhanh tay nào',
		fmt_kr = '#C0xFFF5D6#1. 유저는 길드 보너스를 보내거나 얻을 수 있습니다. 보너스 개수는 제한이 있으므로 서둘러야 합니다.',
		fmt_pt = '#C0xFFF5D6#1. Os jogadores podem enviar Pacotes Vermelhos ou pegar Pacotes Vermelhos na guilda. Como há um número limitado de Pacotes Vermelhos, o dedo mais rápido o pega primeiro!',
		fmt_th = '#C0xFFF5D6#1 ผู้เล่นสามารถส่ง Red Packets หรือคว้า Red Packets ในกิลด์ได้ เนื่องจาก Red Packets มีจำนวนจำกัด นิ้วที่เร็วสุดจะได้ก่อน!'
	},
	[19002] = {
		id = 19002,
		fmt = '#C0xFFF5D6#2.公会红包每天19点自动刷新',
		fmt_tw = '#C0xFFF5D6#2.公會紅包每天19點自動刷新',
		fmt_en = '#C0xFFF5D6#2. Guild Red Packets are automatically refreshed at 19:00 daily',
		fmt_vn = '#C0xFFF5D6#2.19h hàng ngày tự động làm mới Lì Xì Guild',
		fmt_kr = '#C0xFFF5D6#2. 길드 보너스는 매일 19시에 자동 갱신됩니다.',
		fmt_pt = '#C0xFFF5D6#2. Os pacotes vermelhos da guilda são atualizados automaticamente às 19:00 diariamente',
		fmt_th = '#C0xFFF5D6#2 แพ็คเก็ตแดงของกิลด์จะรีเฟรชอัตโนมัติทุกวันเวลา 19:00 น.'
	},
	[19003] = {
		id = 19003,
		fmt = '#C0xFFF5D6#3.提升研究院红包科技的等级可提升公会红包的额度和个数',
		fmt_tw = '#C0xFFF5D6#3.提升研究院紅包科技的等級可提升公會紅包的額度和個數',
		fmt_en = '#C0xFFF5D6#3. Raising the level of the Red Packet Technology Institute can increase the amount and number of guild Red Rackets',
		fmt_vn = '#C0xFFF5D6#3.Tăng cấp Công Nghệ Lì Xì Viện Nghiên Cứu để tăng hạn mức và số lượng Lì Xì Guild',
		fmt_kr = '#C0xFFF5D6#3. 연구소의 보너스 기술 레벨이 증가하면 길드의 보너스 금액과 개수가 증가합니다.',
		fmt_pt = '#C0xFFF5D6#3. Aumentar o nível do Red Packet Technology Institute pode aumentar a quantidade e o número de Red Rackets da guilda',
		fmt_th = '#C0xFFF5D6#3 การเพิ่มระดับของ Red Packet Technology Institute สามารถเพิ่มจำนวนและจำนวน Red Rackets ของกิลด์ได้'
	},
