	[19008] = {
		id = 19008,
		fmt = '#C0xFFF5D6#8.玩家发出的红包保留24小时，到期自动消失，剩余额度不会退回',
		fmt_tw = '#C0xFFF5D6#8.玩家發出的紅包保留24小時，到期自動消失，剩餘額度不會退回',
		fmt_en = '#C0xFFF5D6#8. Red Packets sent by trainers are only valid for 24 hours. It disappears when expires and the remaining amount will not be returned',
		fmt_vn = '#C0xFFF5D6#8.Người chơi phát Lì Xì được lưu trong 24h, hết hạn tự động biến mất, số tiền còn lại không được hoàn trả',
		fmt_kr = '#C0xFFF5D6#8. 유저가 보낸 보너스는 24시간 동안 유지되며, 만료 시 자동으로 사라지고, 잔여 금액은 반환되지 않습니다.',
		fmt_pt = '#C0xFFF5D6#8. Pacotes vermelhos enviados por treinadores são válidos apenas por 24 horas. Eles desaparecem quando expiram e o valor restante não será devolvido',
		fmt_th = '#C0xFFF5D6#8 แพ็คเก็ตสีแดงที่ส่งโดยเทรนเนอร์จะมีอายุใช้งานเพียง 24 ชั่วโมงเท่านั้น แพ็คเก็ตสีแดงจะหายไปเมื่อหมดอายุ และจำนวนเงินที่เหลือจะไม่ถูกส่งคืน'
	},
	[20001] = {
		id = 20001,
		fmt = '欢迎来到公会战，公会战一周为一个赛季，每个赛季都有丰厚奖励哟。快叫上你的战友，一起战斗吧！',
		fmt_tw = '歡迎來到公會戰，公會戰一周為一個賽季，每個賽季都有豐厚獎勵喲。快叫上你的戰友，一起戰鬥吧！',
		fmt_en = 'Welcome to the Guild War! One season of Guild War is conducted once weekly, and each season has plenty of rewards to be won. Invite your comrades and fight together!',
		fmt_vn = 'Chào mừng đến với Guild Chiến, Guild Chiến 1 tuần 1 mùa giải, mỗi mùa đều có nhiều thưởng. Nhanh gọi đồng đội đến cùng chiến đấu thôi!',
		fmt_kr = '길드전에 오신 것을 환영합니다. 길드전은 매주 한 시즌으로 이루어지며, 시즌마다 풍성한 보상이 주어집니다. 동료들과 함께 전투를 진행하세요!',
		fmt_pt = 'Bem-vindo à Guerra de Guildas! Uma temporada de Guerra de Guildas é conduzida uma vez por semana, e cada temporada tem muitas recompensas para serem ganhas. Convide seus camaradas e lutem juntos!',
		fmt_th = 'ยินดีต้อนรับสู่ Guild War! Guild War จัดขึ้นสัปดาห์ละครั้ง 1 ฤดูกาล และในแต่ละฤดูกาลจะมีรางวัลมากมายให้คว้ามา เชิญเพื่อน ๆ ของคุณมาต่อสู้ด้วยกัน!'
	},
	[20002] = {
		id = 20002,
		fmt = '1.公会战分为预选赛、决赛两个阶段：预选赛4天（周二至周五），决赛1天（周六）；',
		fmt_tw = '1.公會戰分為預選賽、決賽兩個階段：預選賽4天（週二至週五），決賽1天（週六）；',
		fmt_en = '1. Guild War is conducted in two stages, the qualifying and final match: 4 days of qualifying match (Tuesday to Friday) and 1 day of final match (Saturday);',
		fmt_vn = '1. Guila Chiến chia thành Vòng Loại và Vòng Chung kết: Vòng Loại 4 ngày (thứ 3- thứ 6), Vòng Chung Kết 1 ngày (thứ 7);',
		fmt_kr = '1. 길드전은 예선전, 결승전의 두 단계로 나뉩니다. 예선전은 4일(화~금), 결승전은 1일(토)간 진행됩니다.',
		fmt_pt = '1. A Guerra de Guildas é realizada em duas etapas, a partida classificatória e a partida final: 4 dias de partida classificatória (terça a sexta) e 1 dia de partida final (sábado);',
		fmt_th = '1. Guild War จัดขึ้นใน 2 รอบ คือ รอบคัดเลือกและรอบชิงชนะเลิศ: รอบคัดเลือก 4 วัน (วันอังคารถึงวันศุกร์) และรอบชิง 1 วัน (วันเสาร์)'
	},
