	[20005] = {
		id = 20005,
		fmt = '4.报名条件：训练家等级到达40级以上、且所在公会等级到达4级及以上的玩家方可报名，只有报名了才能参加当日比赛；',
		fmt_tw = '4.報名條件：訓練家等級到達40級以上、且所在公會等級到達4級及以上的玩家方可報名，只有報名了才能參加當日比賽；',
		fmt_en = '4. Registration eligibility: Only players with trainer and guild level 40 and above can register. Those who have completed the registration can participate in the competition on the same day;',
		fmt_kr = '4. 신청 조건: 트레이너의 레벨이 40 이상이고, 소속 길드가 4레벨 이상인 유저는 참가를 신청할 수 있으며, 신청 후 당일의 경기에 참가할 수 있습니다.',
		fmt_pt = '4. Elegibilidade para registro: Apenas jogadores com nível de treinador e guilda 40 ou superior podem se registrar. Aqueles que concluíram o registro podem participar da competição no mesmo dia;',
		fmt_th = '4. คุณสมบัติในการลงทะเบียน: ผู้เล่นที่มีระดับเทรนเนอร์และกิลด์ 40 ขึ้นไปเท่านั้นจึงจะลงทะเบียนได้ ผู้ที่ลงทะเบียนเสร็จสิ้นสามารถเข้าร่วมการแข่งขันได้ในวันเดียวกัน'
	},
	[20006] = {
		id = 20006,
		fmt = '5.VIP等级到达3及以上的玩家每天战斗开始前半小时，系统会自动报名。',
		fmt_tw = '5.VIP等級到達3及以上的玩家每天戰鬥開始前半小時，系統會自動報名。',
		fmt_en = '5. Players with VIP levels of 3 and above will be registered automatically half an hour before the start of the battle each day.',
		fmt_vn = '5. Người chơi từ VIP3 trở lên được hệ thống tự động đăng ký trước nửa tiếng bắt đầu chiến đấu hàng ngày.',
		fmt_kr = '5. VIP 3레벨 이상의 유저는 매일 전투 시작 30분 전에 시스템이 자동으로 참가 신청을 진행합니다.',
		fmt_pt = '5. Jogadores com nível VIP 3 ou superior serão registrados automaticamente meia hora antes do início da batalha de cada dia.',
		fmt_th = '5. ผู้เล่นที่มีระดับ VIP 3 ขึ้นไปจะได้รับการลงทะเบียนโดยอัตโนมัติครึ่งชั่วโมงก่อนการเริ่มต้นการต่อสู้ในแต่ละวัน'
	},
	[21001] = {
		id = 21001,
		fmt = '1.预选赛期间，周二到周四会限定出战精灵属性类型，具体限制可查看当天报名界面或布阵界面，周五对于精灵属性类型无限制；',
		fmt_tw = '1.預選賽期間，週二到週四會限定出戰精靈屬性類型，具體限制可檢視當天報名介面或佈陣介面，週五對於精靈屬性類型無限制；',
		fmt_en = '1. During the qualifiers, the type of battling Pokémons will be limited from Tuesday to Thursday. You may check the registration interface or the formation interface of the day for specific restrictions. There are no restrictions on the types of Pokémons on Friday;',
		fmt_vn = '1. Trong Vòng Loại, thứ 3-5 giới hạn loại thuộc tính Pokémon, kiểm tra giao diện đăng ký/giao diện bày trận trong ngày để xem giới hạn cụ thể, thứ 6 không giới hạn loại thuộc tính Pokémon;',
		fmt_kr = '1. 예선전 기간 중 화~목요일에는 출전 포켓몬의 타입이 제한되며, 상세한 내용은 당일 신청 메뉴 또는 라인업 메뉴에서 확인할 수 있습니다. 금요일에는 포켓몬의 타입 제한이 없습니다.',
		fmt_pt = '1. Durante as qualificatórias, o tipo de Pokémon de batalha será limitado de terça a quinta-feira. Você pode verificar a interface de registro ou a interface de formação do dia para restrições específicas. Não há restrições sobre os tipos de Pokémon na sexta-feira;',
		fmt_th = '1. ในช่วงรอบคัดเลือก ประเภทของโปเกมอนที่ต่อสู้กันจะถูกจำกัดตั้งแต่วันอังคารถึงวันพฤหัสบดี คุณสามารถตรวจสอบข้อจำกัดเฉพาะได้ที่อินเทอร์เฟซการลงทะเบียนหรืออินเทอร์เฟซการจัดทีมในวันนั้น ไม่มีข้อจำกัดเกี่ยวกับประเภทของโปเกมอนในวันศุกร์'
	},
	[21002] = {
		id = 21002,
		fmt = '2.对于有限制属性的轮次，只要精灵有一种属性符合，即可参与当天的战斗，同进化系列精灵一天只允许使用一次；',
		fmt_tw = '2.對於有限制屬性的輪次，只要精靈有一種屬性符合，即可參與當天的戰鬥，同進化系列精靈一天只允許使用一次；',
		fmt_en = '2. For rounds that limit the Pokémon type, the Pokémon can still join the battle as long as one of the types are allowed. Pokémons of the same evolution series are only allowed once a day;',
		fmt_vn = '2. Các vòng giới hạn thuộc tính, chỉ cần Pokémon có 1 thuộc tính phù hợp đều có thể tham gia chiến đấu trong ngày, Pokémon cùng hệ tiến hoá 1 ngày chỉ sử dụng 1 lần;',
		fmt_kr = '2. 제한 타입 라운드에서는 맞는 타입의 포켓몬이 하나만 있어도 당일의 전투에 참가할 수 있으며, 동일 진화 계열의 포켓몬은 당일 한 번만 사용할 수 있습니다.',
		fmt_pt = '2. Para rodadas que limitam o tipo de Pokémon, o Pokémon ainda pode entrar na batalha, desde que um dos tipos seja permitido. Pokémon da mesma série de evolução são permitidos apenas uma vez por dia;',
		fmt_th = '2. สำหรับรอบที่จำกัดประเภทของโปเกมอน โปเกมอนสามารถเข้าร่วมการต่อสู้ได้ตราบเท่าที่อนุญาตให้มีประเภทใดประเภทหนึ่ง โปเกมอนจากซีรีส์วิวัฒนาการเดียวกันจะได้รับอนุญาตให้เข้าร่วมได้เพียงครั้งเดียวต่อวัน'
	},
	[21003] = {
		id = 21003,
		fmt = '3.预选赛可以派出2队精灵出战，每队可使用3只；',
		fmt_tw = '3.預選賽可以派出2隊精靈出戰，每隊可使用3只；',
		fmt_en = '3. 2 teams of 3 Pokémons can be sent out for the qualifiers;',
		fmt_vn = '3. Vòng Loại có thể điều 2 đội Pokémon ra trận, mỗi đội sử dụng 3 Pokémon;',
		fmt_kr = '3. 예선전에서는 2개 팀의 포켓몬을 출전시킬 수 있고, 각 팀에는 3마리까지 사용할 수 있습니다.',
		fmt_pt = '3. 2 equipes de 3 Pokémon podem ser enviadas para as eliminatórias;',
		fmt_th = '3. สามารถส่งทีมที่มีโปเกมอน 3 ตัว 2 ทีมเข้าแข่งขันรอบคัดเลือกได้'
	},
	[21004] = {
		id = 21004,
		fmt = '4.第一队被击败后，第二队可在下一轮中继续战斗；',
		fmt_tw = '4.第一隊被擊敗後，第二隊可在下一輪中繼續戰鬥；',
		fmt_en = '4. After the first team is defeated, the second team can continue the battle in the next round;',
		fmt_vn = '4. Khi đội 1 bị đánh bại, đội 2 tiếp tục chiến đấu trong vòng tiếp theo;',
		fmt_kr = '4. 첫 부대가 패배하면, 두 번째 부대가 다음 라운드에서 이어서 전투를 진행합니다.',
		fmt_pt = '4. Após a derrota do primeiro time, o segundo time pode continuar a batalha na próxima rodada;',
		fmt_th = '4. หลังจากทีมแรกพ่ายแพ้ ทีมที่สองสามารถดำเนินการต่อสู้ต่อในรอบถัดไป'
	},
	[21005] = {
		id = 21005,
		fmt = '5.比赛形式为混战模式，您将会遇到其他各个公会的玩家（当剩余人数过少时，您可能会与自己公会的成员进行交战决出个人排名）；',
		fmt_tw = '5.比賽形式為混戰模式，您將會遇到其他各個公會的玩家（當剩餘人數過少時，您可能會與自己公會的成員進行交戰決出個人排名）；',
		fmt_en = '5. The tournament is conducted in brawl mode, where you will face players from other guilds (when there are too few remaining players, you may have fight against players from the same guild to decide the individual ranking);',
		fmt_vn = '5. Hình thức thi đấu là chế độ hỗn chiến, bạn sẽ gặp phải người chơi các Guild khác (Khi số người còn lại quá ít, có thể giao chiến với thành viên cùng Guild để quyết định xếp hạng cá nhân); ',
		fmt_kr = '5. 경기는 난투 모드로 진행되며, 다른 길드의 유저와 상대하게 됩니다. (잔여 인원수가 너무 적을 경우, 자신의 길드원과 교전을 진행해 개인 순위를 결정할 수도 있음).',
		fmt_pt = '5. O torneio é realizado no modo briga, onde você enfrentará jogadores de outras guildas (quando houver poucos jogadores restantes, você poderá lutar contra jogadores da mesma guilda para decidir a classificação individual);',
		fmt_th = '5. การแข่งขันจะจัดขึ้นในโหมดต่อสู้ ซึ่งคุณจะได้เผชิญหน้ากับผู้เล่นจากกิลด์อื่น (เมื่อผู้เล่นเหลือน้อยเกินไป คุณอาจต้องต่อสู้กับผู้เล่นจากกิลด์เดียวกันเพื่อตัดสินอันดับของแต่ละบุคคล)'
	},
	[21006] = {
		id = 21006,
		fmt = '6.胜利的玩家，可继续进行下一轮战斗，与保留下来的对手继续鏖战；',
