	[22303] = {
		id = 22303,
		fmt = '3.比赛结束后，奖励统一以邮件形式发放，竞猜对冠军可获得押注倍率的金额，竞猜目标为第二名时返还一半押注金额。',
		fmt_tw = '3.比賽結束後，獎勵統一以郵件形式發放，競猜對冠軍可獲得押註倍率的金額，競猜目標為第二名時返還一半押註金額。',
		fmt_en = '3. When the tournament ends, rewards will all be sent via mail. Those who have guessed the champion correctly will receive rewards according to the odds, and if the contestant wins the second place, you get half of the bets you placed',
