		fmt_th = '#C0xFFF5D6#3 วางเดิมพันกับแชมเปี้ยน ยิ่งอัตราเดิมพันสูง ผลตอบแทนก็ยิ่งมากขึ้น คุณสามารถชนะรางวัลได้มากถึง 1,500,000 เหรียญในแต่ละฤดูกาล'
	},
	[30004] = {
		id = 30004,
		fmt = '#C0xFFF5D6#4、如下注对象进入四强则返还1.5倍金额，未进入四强则返还一半金额',
		fmt_tw = '#C0xFFF5D6#4、如下註物件進入四強則返還1.5倍金額，未進入四強則返還一半金額',
