	[31001] = {
		id = 31001,
		fmt = '#C0x08ED1F#宠物们发现了一片盛产矿石的大陆，传闻在该大陆的商店中能用矿石兑换丰厚的奖励，因此驯兽师们纷纷加入了矿石的争夺中。',
		fmt_tw = '#C0x08ED1F#寵物們發現了一片盛產礦石的大陸，傳聞在該大陸的商店中能用礦石兌換豐厚的獎勵，因此馴獸師們紛紛加入了礦石的爭奪中。',
		fmt_en = '#C0x08ED1F#The Pokémons found a land rich in ore. It\'s said that ores can be exchanged for rich rewards in a shop on the land, and since then Mine War has begun among the trainers.',
		fmt_vn = '#C0x08ED1F# Pet phát hiện 1 lục địa giàu khoáng, nghe nói có thể dùng khoáng đổi thưởng trong Shop của lục địa này, vì vậy các HLV đều đã tham gia tranh đoạt khoáng.',
		fmt_kr = '#C0x08ED1F#포켓몬들은 광석으로 가득한 대륙을 발견했습니다. 소문에 따르면 이 대륙의 상점에서는 광석을 사용해 다양한 보상과 교환할 수 있다고 합니다. 이에 많은 트레이너들이 광석 쟁탈에 나섰습니다.',
		fmt_pt = '#C0x08ED1F#Os Pokémons encontraram uma terra rica em minério. Dizem que minérios podem ser trocados por recompensas ricas em uma loja na terra, e desde então a Guerra das Minas começou entre os treinadores.',
		fmt_th = '#C0x08ED1F#เหล่าโปเกมอนพบดินแดนที่อุดมไปด้วยแร่ ว่ากันว่าแร่สามารถนำไปแลกรางวัลอันล้ำค่าได้ที่ร้านค้าบนดินแดนนั้น และนับตั้งแต่นั้นมา สงครามเหมืองก็เริ่มขึ้นระหว่างเหล่าเทรนเนอร์'
	},
