		fmt_th = '#C0xFFF5D6#3 ผู้ฝึกสอนมีโอกาส 5 ครั้งในการแก้แค้น ซึ่งไม่ขึ้นอยู่กับโอกาสในการปล้น'
	},
	[35001] = {
