		fmt_th = '1. ผู้ฝึกสอนโปเกมอนสามารถย่อยสลายรูนสโตนส่วนเกินได้โดยไม่ต้องใช้วัสดุใดๆ'
	},
	[84002] = {
		id = 84002,
		fmt = '2.对于已培养过的符石，分解后将100%返还消耗的强化材料和金币',
		fmt_tw = '2.對於已培養過的符石，分解後將100%返還消耗的強化材料和金幣',
		fmt_en = '2. 100% of the materials and coins used in gem enhancement will be returned when decomposing enhanced runestones.',
		fmt_kr = '2. 이미 육성한 룬스톤 분해 시 소모한 강화 재료와 코인을 100% 반환합니다.',
		fmt_pt = '2. 100% dos materiais e moedas usados no aprimoramento de gemas serão devolvidos ao decompor runas aprimoradas.',
		fmt_th = '2. วัตถุดิบและเหรียญที่ใช้ในการปรับปรุงอัญมณี 100% จะถูกส่งคืนเมื่อทำการสลายรูนสโตนที่ปรับปรุงแล้ว'
	},
	[84003] = {
		id = 84003,
		fmt = '3.镶嵌中的符石不能分解，也无法在符石分解内查看',
