		fmt_th = '2. โปเกมอนที่พัฒนาร่างแล้วจะมีสถิติพื้นฐานที่สูงกว่าเมื่อใช้กับสถิติที่ฝึกมาทั้งหมด ประเภทและความหายาก #C0xF76B45##L10# อาจเปลี่ยนแปลงได้ #C0x5B545B#'
	},
	[95003] = {
		id = 95003,
		fmt = '3.精灵需要培养至一定阶段后才可以进行超进化；且主要消耗两类特殊的道具：钥石和专属的超级进化石。',
