	[97001] = {
		id = 97001,
		fmt = '1.专属的超级石可以通过消耗#C0xF76B45##L10#同属性且同稀有度的精灵#C0x5B545B#或者#C0xF76B45##L10#同属性且同稀有度的精灵碎片#C0x5B545B#转化获得，且每日有一定的转化数量限制:',
		fmt_tw = '1.專屬的超級石可以通過消耗#C0xF76B45##L10#同屬性且同稀有度的精靈#C0x5B545B#或者#C0xF76B45##L10#同屬性且同稀有度的精靈碎片#C0x5B545B#轉化獲得，且每日有一定的轉化數量限制:',
		fmt_en = '1. Exclusive Super Stones are available by consuming #C0xF76B45##L10#Pokémon with the same Type and Rarity#C0x5B545B# or converting #C0xF76B45##L10#Shards of Pokémon with the same Type and Rarity#C0x5B545B#. Daily converts limited:',
		fmt_kr = '1. 전용 메가스톤은 #C0xF76B45##L10#동일 속성 및 동일 희귀도의 포켓몬#C0x5B545B#을 소모하거나 #C0xF76B45##L10#동일 속성 및 동일 희귀도 포켓몬의 조각#C0x5B545B#을 전환해 획득하며, 매일 전환 수량에는 제한이 있습니다:',
		fmt_pt = '1. Super Stones exclusivas estão disponíveis ao consumir #C0xF76B45##L10#Pokémon com o mesmo Tipo e Raridade#C0x5B545B# ou converter #C0xF76B45##L10#Shards de Pokémon com o mesmo Tipo e Raridade#C0x5B545B#. Conversões diárias limitadas:',
		fmt_th = '1. สามารถรับ Super Stone สุดพิเศษได้โดยใช้ #C0xF76B45##L10#Pokémon ที่มีประเภทและระดับความหายากเดียวกัน#C0x5B545B# หรือแปลง #C0xF76B45##L10#Shards ของ Pokémon ที่มีประเภทและระดับความหายากเดียวกัน#C0x5B545B# จำกัดการแปลงรายวัน:'
	},
	[97002] = {
		id = 97002,
		fmt = '①每个A级同属性精灵或紫色百变怪可转化10个紫色品质的超级石,每3个A级碎片可转化1个紫色品质的超级石',
		fmt_tw = '①每個A級同屬性精靈或紫色百變怪可轉化10個紫色品質的超級石,每3個A級碎片可轉化1個紫色品質的超級石',
		fmt_en = '①1 Rank-A Pokémon with the same Type or Purple Ditto can be converted into 10 Purple Super Stones; 3 Rank-A Shards can be converted into 1 Purple Super Sone.',
		fmt_kr = '①A급 동일 속성 포켓몬 또는 보라색 메타몽은 보라색 등급의 메가스톤 10개, A급 조각 3개는 보라색 등급의 메가스톤 1개로 전환 가능',
		fmt_pt = '①1 Pokémon de Nível A com o mesmo Tipo ou Ditto Roxo pode ser convertido em 10 Super Pedras Roxas; 3 Fragmentos de Nível A podem ser convertidos em 1 Super Sone Roxo.',
		fmt_th = '①โปเกมอนระดับ A 1 ตัวที่มีประเภทเดียวกันหรือ Ditto สีม่วงสามารถแปลงเป็น Super Stone สีม่วงได้ 10 ก้อน; เศษระดับ A 3 ชิ้นสามารถแปลงเป็น Super Sone สีม่วงได้ 1 ชิ้น'
	},
	[97003] = {
		id = 97003,
		fmt = '②每个S级同属性精灵或橙色百变怪可转化10个橙色品质的超级石,每5个S级碎片可转化1个橙色品质的超级石',
		fmt_tw = '②每個S級同屬性精靈或橙色百變怪可轉化10個橙色品質的超級石,每5個S級碎片可轉化1個橙色品質的超級石',
		fmt_en = '②1 Rank-S Pokémon with the same Type or Orange Ditto can be converted into 10 Orange Super Stones; 5 Rank-S Shards can be converted into 1 Orange Super Stone.',
		fmt_kr = '②S급 동일 속성 포켓몬 또는 주황색 메타몽은 주황색 등급의 메가스톤 10개, S급 조각 5개는 주황색 등급의 메가스톤 1개로 전환 가능',
		fmt_pt = '②1 Pokémon Rank-S com o mesmo Tipo ou Ditto Laranja pode ser convertido em 10 Super Pedras Laranja; 5 Fragmentos Rank-S podem ser convertidos em 1 Super Pedra Laranja.',
		fmt_th = '②โปเกมอนระดับ S 1 ตัวที่มีประเภทเดียวกันหรือ Orange Ditto สามารถแปลงเป็น Orange Super Stone ได้ 10 ก้อน; เศษระดับ S 5 ชิ้นสามารถแปลงเป็น Orange Super Stone ได้ 1 ก้อน'
	},
	[97004] = {
		id = 97004,
		fmt = '③每个S+级同属性精灵或红色百变怪可转化10个红色品质的超级石,每8个S+级碎片可转化1个红色品质的超级石',
		fmt_tw = '③每個S+級同屬性精靈或紅色百變怪可轉化10個紅色品質的超級石,每8個S+級碎片可轉化1個紅色品質的超級石',
		fmt_en = '③1 Rank-S+ Pokémon with the same Type or Red Ditto can be converted into 10 Red Super Stones; 8 Rank-S+ Shards can be converted into 1 Red Super Stone.',
		fmt_kr = '③S+급 동일 속성 포켓몬 또는 빨간색 메타몽은 빨간색 등급의 메가스톤 10개, S+급 조각 8개는 빨간색 등급의 메가스톤 1개로 전환 가능',
		fmt_pt = '③1 Pokémon Rank-S+ com o mesmo Tipo ou Red Ditto pode ser convertido em 10 Red Super Stones; 8 Fragmentos Rank-S+ podem ser convertidos em 1 Red Super Stone.',
		fmt_th = '③โปเกมอนระดับ S+ 1 ตัวที่มีประเภทหรือ Red Ditto เดียวกันสามารถแปลงเป็น Red Super Stone ได้ 10 ก้อน; โปเกมอนระดับ S+ 8 ชิ้นสามารถแปลงเป็น Red Super Stone ได้ 1 ก้อน'
	},
	[97005] = {
