	[125508] = {
		id = 125508,
		fmt = '1.部屋大作战以 #C0xF76B45#四周#C0x5B545B#为一个赛季，收集三周的公会战积分排名信息后，第四周开启',
		fmt_pt = '1. A batalha de guildas é dividida em quatro semanas com #C0xF76B45##C0x5B545B# como uma temporada. Após coletar três semanas de informações de classificação de pontos de guerra de guildas, a quarta semana começará.',
		fmt_th = '1. การต่อสู้ของกิลด์จะแบ่งออกเป็น 4 สัปดาห์ โดย #C0xF76B45##C0x5B545B# เป็น 1 ฤดูกาล หลังจากรวบรวมข้อมูลอันดับคะแนนของสงครามกิลด์ครบ 3 สัปดาห์แล้ว สัปดาห์ที่ 4 ก็จะเริ่มต้นขึ้น'
